import type { Metadata } from "next";
import LoanApplication from "./LoanApplication";

export const metadata: Metadata = {
  title: "住宅ローン仮審査申込 | ぐんじょう銀行",
  description:
    "借入希望額・返済期間をシミュレーションし、月々返済額を確認しながらお申込みいただけます。",
};

export default function LoanPage() {
  return <LoanApplication />;
}

/**
 * Loan / amortization math. @gunjo/ui ships number/currency formatters but no
 * finance helpers, so the amortized-payment formula and schedule live here.
 * (FINDING: no loan-math primitive in the design system.)
 */

export interface AmortizationRow {
  /** 1-based payment number (回). */
  period: number;
  /** Scheduled payment for this period (返済額). */
  payment: number;
  /** Portion applied to principal (元金). */
  principal: number;
  /** Portion applied to interest (利息). */
  interest: number;
  /** Remaining balance after this payment (残高). */
  balance: number;
}

export interface LoanSummary {
  monthlyPayment: number;
  totalPayment: number;
  totalInterest: number;
}

/**
 * Standard fixed-rate amortized monthly payment.
 * P = principal, annualRatePct = e.g. 1.2 (%), years = term.
 * Handles the 0% edge case (straight-line).
 */
export function monthlyPayment(
  principal: number,
  annualRatePct: number,
  years: number
): number {
  const n = years * 12;
  if (n <= 0) return 0;
  const r = annualRatePct / 100 / 12;
  if (r === 0) return principal / n;
  const factor = Math.pow(1 + r, n);
  return (principal * r * factor) / (factor - 1);
}

export function loanSummary(
  principal: number,
  annualRatePct: number,
  years: number
): LoanSummary {
  const pay = monthlyPayment(principal, annualRatePct, years);
  const n = years * 12;
  const total = pay * n;
  return {
    monthlyPayment: Math.round(pay),
    totalPayment: Math.round(total),
    totalInterest: Math.round(total - principal),
  };
}

/**
 * Full amortization schedule. The final period absorbs rounding so the balance
 * lands exactly on 0 (no lingering ¥1 残高 at term end).
 */
export function amortizationSchedule(
  principal: number,
  annualRatePct: number,
  years: number
): AmortizationRow[] {
  const n = years * 12;
  if (n <= 0) return [];
  const r = annualRatePct / 100 / 12;
  const pay = monthlyPayment(principal, annualRatePct, years);
  const rows: AmortizationRow[] = [];
  let balance = principal;

  for (let period = 1; period <= n; period++) {
    const interest = Math.round(balance * r);
    let principalPaid = Math.round(pay - interest);
    // Last period: pay off whatever is left so the schedule reaches ~0.
    if (period === n || principalPaid > balance) {
      principalPaid = balance;
    }
    const payment = principalPaid + interest;
    balance = balance - principalPaid;
    rows.push({
      period,
      payment,
      principal: principalPaid,
      interest,
      balance: Math.max(0, balance),
    });
    if (balance <= 0) break;
  }
  return rows;
}

/** 返済負担率 = annual repayment / annual income. */
export function debtToIncomeRatio(
  monthly: number,
  annualIncomeManen: number
): number {
  if (annualIncomeManen <= 0) return 0;
  const annualRepayment = monthly * 12;
  return annualRepayment / (annualIncomeManen * 10_000);
}

"use client";

import * as React from "react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Checkbox,
  Container,
  FileUploader,
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormLabel,
  FormMessage,
  Input,
  Progress,
  Select,
  Separator,
  Slider,
  Spinner,
  Statistic,
  StatusScreen,
  Stepper,
  ThemeProvider,
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  ToggleGroup,
  ToggleGroupItem,
  formatCurrency,
  formatPercent,
  type FileUploaderProgressResolver,
} from "@gunjo/ui";
import {
  IconCircleCheck,
  IconAlertTriangle,
  IconCircleX,
} from "@tabler/icons-react";
import {
  amortizationSchedule,
  debtToIncomeRatio,
  loanSummary,
} from "./loan-math";

/* ------------------------------------------------------------------ */
/* Simulator constants                                                 */
/* ------------------------------------------------------------------ */

const AMOUNT_MIN = 5_000_000;
const AMOUNT_MAX = 100_000_000;
const AMOUNT_STEP = 1_000_000;
const YEARS_MIN = 5;
const YEARS_MAX = 35;
const RATE_FIXED = 1.85; // 固定金利 (例)
const RATE_VARIABLE = 0.475; // 変動金利 (例)

type RateType = "fixed" | "variable";

const EMPLOYMENT_OPTIONS = [
  { value: "", label: "選択してください" },
  { value: "seishain", label: "正社員" },
  { value: "keiyaku", label: "契約社員" },
  { value: "haken", label: "派遣社員" },
  { value: "jieigyo", label: "自営業" },
  { value: "yakuin", label: "会社役員" },
  { value: "part", label: "パート・アルバイト" },
] as const;

/* ------------------------------------------------------------------ */
/* Applicant form types + validation                                   */
/* ------------------------------------------------------------------ */

interface ApplicantForm {
  name: string;
  birthdate: string;
  income: string; // 年収 (万円)
  tenure: string; // 勤続年数
  employment: string;
  existingDebt: string; // 既存借入 月額 (円)
}

type ApplicantErrors = Partial<Record<keyof ApplicantForm, string>>;

const EMPTY_APPLICANT: ApplicantForm = {
  name: "",
  birthdate: "",
  income: "",
  tenure: "",
  employment: "",
  existingDebt: "",
};

function validateApplicant(form: ApplicantForm): ApplicantErrors {
  const errors: ApplicantErrors = {};
  if (!form.name.trim()) errors.name = "氏名を入力してください。";
  if (!form.birthdate) errors.birthdate = "生年月日を入力してください。";
  const income = Number(form.income);
  if (!form.income.trim()) errors.income = "年収を入力してください。";
  else if (Number.isNaN(income) || income <= 0)
    errors.income = "年収は1以上の数値で入力してください。";
  const tenure = Number(form.tenure);
  if (!form.tenure.trim()) errors.tenure = "勤続年数を入力してください。";
  else if (Number.isNaN(tenure) || tenure < 0)
    errors.tenure = "勤続年数は0以上の数値で入力してください。";
  if (!form.employment) errors.employment = "雇用形態を選択してください。";
  if (form.existingDebt.trim()) {
    const debt = Number(form.existingDebt);
    if (Number.isNaN(debt) || debt < 0)
      errors.existingDebt = "既存借入は0以上の数値で入力してください。";
  }
  return errors;
}

/* ------------------------------------------------------------------ */
/* Document upload categories                                          */
/* ------------------------------------------------------------------ */

type DocCategory = "identity" | "income" | "property";

const DOC_CATEGORIES: {
  key: DocCategory;
  title: string;
  hint: string;
}[] = [
  {
    key: "identity",
    title: "本人確認書類",
    hint: "運転免許証・マイナンバーカード等（表裏）。JPG / PNG / PDF・5MBまで。",
  },
  {
    key: "income",
    title: "収入証明",
    hint: "源泉徴収票・確定申告書・課税証明書等。JPG / PNG / PDF・5MBまで。",
  },
  {
    key: "property",
    title: "物件資料",
    hint: "売買契約書・物件概要・間取り図等。JPG / PNG / PDF・5MBまで。",
  },
];

const DOC_ACCEPT = {
  "image/jpeg": [".jpg", ".jpeg"],
  "image/png": [".png"],
  "application/pdf": [".pdf"],
};

const UPLOADER_LABELS = {
  browse: "ファイルを選択",
  drop: "またはここにドラッグ＆ドロップ",
  maxSize: (mb: number) => `1ファイル ${mb}MB まで`,
  removeFile: "削除",
  fileTooLarge: "ファイルサイズが大きすぎます",
  fileTypeNotAccepted: "対応していないファイル形式です",
  status: {
    pending: "待機中",
    uploading: "アップロード中",
    complete: "完了",
    error: "エラー",
  },
} as const;

/* Simulate per-file upload progress so reviewers see uploading→done state. */
function useUploadProgress(files: File[]): FileUploaderProgressResolver {
  const [progress, setProgress] = React.useState<
    Record<string, { progress: number; status: "uploading" | "complete" }>
  >({});

  React.useEffect(() => {
    files.forEach((file) => {
      const key = file.name;
      setProgress((prev) =>
        prev[key] ? prev : { ...prev, [key]: { progress: 0, status: "uploading" } }
      );
    });
  }, [files]);

  React.useEffect(() => {
    const id = window.setInterval(() => {
      setProgress((prev) => {
        let changed = false;
        const next = { ...prev };
        for (const key of Object.keys(next)) {
          const entry = next[key];
          if (entry.status === "complete") continue;
          const bumped = Math.min(100, entry.progress + 25);
          next[key] = {
            progress: bumped,
            status: bumped >= 100 ? "complete" : "uploading",
          };
          changed = true;
        }
        return changed ? next : prev;
      });
    }, 500);
    return () => window.clearInterval(id);
  }, []);

  return progress;
}

function DocumentUploader({
  category,
}: {
  category: (typeof DOC_CATEGORIES)[number];
}) {
  const [files, setFiles] = React.useState<File[]>([]);
  const fileProgress = useUploadProgress(files);
  return (
    <div className="grid gap-2">
      <div className="flex flex-wrap items-baseline justify-between gap-2">
        <h3 className="text-sm font-semibold text-foreground">
          {category.title}
        </h3>
        <Badge variant={files.length > 0 ? "success" : "outline"}>
          {files.length > 0 ? `${files.length}件` : "未提出"}
        </Badge>
      </div>
      <FileUploader
        value={files}
        onValueChange={setFiles}
        maxFiles={5}
        maxSize={5 * 1024 * 1024}
        accept={DOC_ACCEPT}
        fileProgress={fileProgress}
        labels={UPLOADER_LABELS}
        className="max-w-full"
        aria-label={`${category.title}のアップロード`}
      />
      <p className="text-xs text-muted-foreground">{category.hint}</p>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Decision logic                                                      */
/* ------------------------------------------------------------------ */

type Decision = "approved" | "conditional" | "declined";

interface DecisionResult {
  decision: Decision;
  maxLoan: number;
  reason: string;
  conditions: string[];
  receiptNo: string;
  timestamp: string;
}

function decide(
  amount: number,
  monthly: number,
  income: number,
  dti: number
): DecisionResult {
  const receiptNo = `KR-${new Date().getFullYear()}-${Math.floor(
    100000 + Math.random() * 899999
  )}`;
  const timestamp = new Intl.DateTimeFormat("ja-JP", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  }).format(new Date());

  // 借入可能額の目安: 返済負担率35%以内 ＆ 年収の概ね8倍を上限に。
  const maxByIncome = income * 10_000 * 8;

  if (dti > 0.45) {
    return {
      decision: "declined",
      maxLoan: 0,
      reason:
        "返済負担率が当行基準（45%）を超えています。借入希望額の引き下げ、または返済期間の延長をご検討ください。",
      conditions: [],
      receiptNo,
      timestamp,
    };
  }
  if (dti > 0.35 || amount > maxByIncome) {
    return {
      decision: "conditional",
      maxLoan: Math.min(amount, maxByIncome),
      reason:
        "返済負担率または借入希望額が目安を上回るため、追加書類による本審査が必要です。",
      conditions: [
        "源泉徴収票（直近2年分）の提出",
        "勤続年数・雇用形態の確認",
        "借入希望額の見直しのご相談",
      ],
      receiptNo,
      timestamp,
    };
  }
  return {
    decision: "approved",
    maxLoan: Math.max(amount, Math.min(maxByIncome, amount * 1.1)),
    reason: "仮審査の基準を満たしています。",
    conditions: [
      "本審査時に提出書類の原本確認を行います",
      "団体信用生命保険へのご加入が必要です",
    ],
    receiptNo,
    timestamp,
  };
}

/* ------------------------------------------------------------------ */
/* Slider field — adds the value label + unit + aria-valuetext the      */
/* design system's bare Slider does not render. (FINDING)               */
/* ------------------------------------------------------------------ */

function SliderField({
  id,
  label,
  value,
  min,
  max,
  step,
  onChange,
  format,
  valueText,
}: {
  id: string;
  label: string;
  value: number;
  min: number;
  max: number;
  step: number;
  onChange: (v: number) => void;
  format: (v: number) => string;
  valueText: (v: number) => string;
}) {
  return (
    <div className="grid gap-2">
      <div className="flex items-baseline justify-between gap-3">
        <label htmlFor={id} className="text-sm font-medium text-foreground">
          {label}
        </label>
        <output
          htmlFor={id}
          className="text-lg font-bold tabular-nums text-foreground"
        >
          {format(value)}
        </output>
      </div>
      <Slider
        id={id}
        min={min}
        max={max}
        step={step}
        value={value}
        onValueChange={onChange}
        aria-label={label}
        aria-valuetext={valueText(value)}
      />
      <div className="flex justify-between text-xs text-muted-foreground tabular-nums">
        <span>{format(min)}</span>
        <span>{format(max)}</span>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Main component                                                      */
/* ------------------------------------------------------------------ */

export default function LoanApplication() {
  // gunjo's dark tokens are `.dark`-class-based, not `@media`-based. The library
  // ships ThemeProvider precisely to bridge prefers-color-scheme → `.dark`, so a
  // consumer must opt in for dark mode to work. (FINDING.)
  return (
    <ThemeProvider defaultTheme="system" enablePersistence={false}>
      <LoanApplicationInner />
    </ThemeProvider>
  );
}

function LoanApplicationInner() {
  // Simulator state
  const [amount, setAmount] = React.useState(35_000_000);
  const [years, setYears] = React.useState(35);
  const [rateType, setRateType] = React.useState<RateType>("fixed");
  const rate = rateType === "fixed" ? RATE_FIXED : RATE_VARIABLE;

  const summary = React.useMemo(
    () => loanSummary(amount, rate, years),
    [amount, rate, years]
  );
  const schedule = React.useMemo(
    () => amortizationSchedule(amount, rate, years),
    [amount, rate, years]
  );
  const scheduleHead = schedule.slice(0, 12);

  // Applicant form state
  const [form, setForm] = React.useState<ApplicantForm>(EMPTY_APPLICANT);
  const [errors, setErrors] = React.useState<ApplicantErrors>({});
  const [submitted, setSubmitted] = React.useState(false);

  const updateField = (key: keyof ApplicantForm, value: string) => {
    setForm((prev) => ({ ...prev, [key]: value }));
    if (submitted) {
      setErrors(validateApplicant({ ...form, [key]: value }));
    }
  };

  // Debt-to-income — uses the entered 年収 if present, else the worst case is
  // not shown. Existing debt is added to the new loan's monthly repayment.
  const incomeManen = Number(form.income) || 0;
  const existingMonthly = Number(form.existingDebt) || 0;
  const dti = React.useMemo(
    () =>
      incomeManen > 0
        ? debtToIncomeRatio(summary.monthlyPayment + existingMonthly, incomeManen)
        : null,
    [summary.monthlyPayment, existingMonthly, incomeManen]
  );
  const dtiOver = dti !== null && dti > 0.35;

  // Consent
  const [consentCredit, setConsentCredit] = React.useState(false);
  const [consentTerms, setConsentTerms] = React.useState(false);
  const allConsented = consentCredit && consentTerms;

  // Result flow
  const [phase, setPhase] = React.useState<"form" | "processing" | "result">(
    "form"
  );
  const [result, setResult] = React.useState<DecisionResult | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
    const v = validateApplicant(form);
    setErrors(v);
    if (Object.keys(v).length > 0 || !allConsented) return;

    setPhase("processing");
    window.setTimeout(() => {
      setResult(
        decide(amount, summary.monthlyPayment, incomeManen, dti ?? 0)
      );
      setPhase("result");
    }, 1800);
  };

  const handleReset = () => {
    setPhase("form");
    setResult(null);
    setSubmitted(false);
  };

  const steps = [
    { label: "シミュレーション", state: "completed" as const },
    {
      label: "申込者情報",
      state:
        phase === "form" ? ("current" as const) : ("completed" as const),
    },
    {
      label: "書類・同意",
      state:
        phase === "form" ? ("upcoming" as const) : ("completed" as const),
    },
    {
      label: "仮審査結果",
      state:
        phase === "result" ? ("current" as const) : ("upcoming" as const),
    },
  ];

  /* ---------------- Result screen ---------------- */
  if (phase === "result" && result) {
    return (
      <ResultScreen result={result} steps={steps} onReset={handleReset} />
    );
  }

  return (
    <main className="min-h-full bg-background py-8 sm:py-10">
      <Container size="lg" className="flex flex-col gap-8">
        {/* Header */}
        <header className="flex flex-col gap-3">
          <Badge variant="info" className="w-fit">
            ぐんじょう銀行
          </Badge>
          <h1 className="text-2xl font-bold tracking-tight text-foreground sm:text-3xl">
            住宅ローン仮審査申込
          </h1>
          <p className="max-w-2xl text-sm text-muted-foreground">
            借入希望額と返済期間をシミュレーションし、月々のご返済額をご確認いただきながらお申込みいただけます。仮審査結果は最短当日にご回答します。
          </p>
          <div className="overflow-x-auto">
            <Stepper steps={steps} aria-label="申込ステップ" />
          </div>
        </header>

        {/* Processing overlay state */}
        {phase === "processing" ? (
          <Card>
            <CardContent className="flex flex-col items-center gap-4 py-16 text-center">
              <Spinner size="lg" aria-hidden="true" />
              <p role="status" aria-live="polite" className="text-sm font-medium text-foreground">
                仮審査を実施しています…
              </p>
              <p className="text-xs text-muted-foreground">
                信用情報を照会し、返済負担率を確認しています。しばらくお待ちください。
              </p>
            </CardContent>
          </Card>
        ) : (
          <>
            {/* ===== 1. Simulator ===== */}
            <section aria-labelledby="sim-heading">
              <Card>
                <CardHeader>
                  <CardTitle as="h2" id="sim-heading">
                    ローンシミュレーター
                  </CardTitle>
                  <CardDescription>
                    スライダーを動かすと、月々のご返済額がリアルタイムで再計算されます。
                  </CardDescription>
                </CardHeader>
                <CardContent className="grid gap-6">
                  <div className="grid gap-6 lg:grid-cols-2">
                    <SliderField
                      id="sim-amount"
                      label="借入希望額"
                      value={amount}
                      min={AMOUNT_MIN}
                      max={AMOUNT_MAX}
                      step={AMOUNT_STEP}
                      onChange={setAmount}
                      format={(v) => formatCurrency(v)}
                      valueText={(v) => formatCurrency(v)}
                    />
                    <SliderField
                      id="sim-years"
                      label="返済期間"
                      value={years}
                      min={YEARS_MIN}
                      max={YEARS_MAX}
                      step={1}
                      onChange={setYears}
                      format={(v) => `${v}年`}
                      valueText={(v) => `${v}年`}
                    />
                  </div>

                  {/* Rate type toggle */}
                  <div className="grid gap-2">
                    <span id="rate-label" className="text-sm font-medium text-foreground">
                      金利タイプ
                    </span>
                    <div className="flex flex-wrap items-center gap-3">
                      <ToggleGroup
                        type="single"
                        value={rateType}
                        disallowEmpty
                        onValueChange={(v) => v && setRateType(v as RateType)}
                        variant="outline"
                        aria-labelledby="rate-label"
                      >
                        <ToggleGroupItem value="fixed">固定金利</ToggleGroupItem>
                        <ToggleGroupItem value="variable">変動金利</ToggleGroupItem>
                      </ToggleGroup>
                      <span className="text-sm text-muted-foreground tabular-nums">
                        適用金利{" "}
                        <span className="font-semibold text-foreground">
                          年 {formatPercent(rate, { asPercentValue: true, maximumFractionDigits: 3 })}
                        </span>
                      </span>
                    </div>
                  </div>

                  <Separator />

                  {/* KPI row */}
                  <div className="grid gap-4 sm:grid-cols-3">
                    <Statistic
                      label="月々返済額"
                      value={formatCurrency(summary.monthlyPayment)}
                      hint="ボーナス払いなし"
                    />
                    <Statistic
                      label="総返済額"
                      value={formatCurrency(summary.totalPayment)}
                      hint={`${years}年 / ${years * 12}回`}
                    />
                    <Statistic
                      label="利息総額"
                      value={formatCurrency(summary.totalInterest)}
                      tone="neutral"
                    />
                  </div>
                </CardContent>
              </Card>
            </section>

            {/* ===== 2. Amortization schedule ===== */}
            <section aria-labelledby="schedule-heading">
              <Card>
                <CardHeader>
                  <CardTitle as="h2" id="schedule-heading">
                    返済予定表（最初の12回）
                  </CardTitle>
                  <CardDescription>
                    元金・利息の内訳と残高の推移です。残高は最終回に0円となります。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  {/* Desktop / tablet: real table */}
                  <div className="hidden sm:block">
                    <Table striped>
                      <TableCaption>
                        全{schedule.length}回中、最初の12回を表示しています。
                      </TableCaption>
                      <TableHeader>
                        <TableRow>
                          <TableHead scope="col">回</TableHead>
                          <TableHead scope="col" className="text-right">
                            返済額
                          </TableHead>
                          <TableHead scope="col" className="text-right">
                            元金
                          </TableHead>
                          <TableHead scope="col" className="text-right">
                            利息
                          </TableHead>
                          <TableHead scope="col" className="text-right">
                            残高
                          </TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {scheduleHead.map((row) => (
                          <TableRow key={row.period}>
                            <TableHead scope="row" className="font-medium text-foreground">
                              {row.period}
                            </TableHead>
                            <TableCell className="text-right tabular-nums">
                              {formatCurrency(row.payment)}
                            </TableCell>
                            <TableCell className="text-right tabular-nums">
                              {formatCurrency(row.principal)}
                            </TableCell>
                            <TableCell className="text-right tabular-nums">
                              {formatCurrency(row.interest)}
                            </TableCell>
                            <TableCell className="text-right tabular-nums">
                              {formatCurrency(row.balance)}
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>

                  {/* Mobile: stacked cards (a wide table just scrolls off-screen) */}
                  <ul className="grid gap-3 sm:hidden">
                    {scheduleHead.map((row) => (
                      <li
                        key={row.period}
                        className="rounded-lg border border-border bg-card p-4"
                      >
                        <div className="mb-2 flex items-center justify-between">
                          <span className="text-sm font-semibold text-foreground">
                            第 {row.period} 回
                          </span>
                          <span className="text-sm font-bold tabular-nums text-foreground">
                            {formatCurrency(row.payment)}
                          </span>
                        </div>
                        <dl className="grid grid-cols-2 gap-x-4 gap-y-1 text-xs">
                          <dt className="text-muted-foreground">元金</dt>
                          <dd className="text-right tabular-nums">
                            {formatCurrency(row.principal)}
                          </dd>
                          <dt className="text-muted-foreground">利息</dt>
                          <dd className="text-right tabular-nums">
                            {formatCurrency(row.interest)}
                          </dd>
                          <dt className="text-muted-foreground">残高</dt>
                          <dd className="text-right tabular-nums">
                            {formatCurrency(row.balance)}
                          </dd>
                        </dl>
                      </li>
                    ))}
                  </ul>
                </CardContent>
              </Card>
            </section>

            {/* ===== 3+4+5. Applicant form, upload, consent (one <form>) ===== */}
            <Form onSubmit={handleSubmit} noValidate className="flex flex-col gap-8">
              {/* Applicant info */}
              <section aria-labelledby="applicant-heading">
                <Card>
                  <CardHeader>
                    <CardTitle as="h2" id="applicant-heading">
                      申込者情報
                    </CardTitle>
                    <CardDescription>
                      仮審査に必要な情報をご入力ください。<span aria-hidden="true" className="text-destructive">*</span> は必須項目です。
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="grid gap-2 sm:grid-cols-2">
                    <FormField error={errors.name} required>
                      <FormLabel>氏名</FormLabel>
                      <FormControl>
                        <Input
                          value={form.name}
                          onChange={(e) => updateField("name", e.target.value)}
                          placeholder="群青 太郎"
                          autoComplete="name"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormField>

                    <FormField error={errors.birthdate} required>
                      <FormLabel>生年月日</FormLabel>
                      <FormControl>
                        <Input
                          type="date"
                          value={form.birthdate}
                          onChange={(e) => updateField("birthdate", e.target.value)}
                          autoComplete="bday"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormField>

                    <FormField error={errors.income} required>
                      <FormLabel>年収（万円）</FormLabel>
                      <FormControl>
                        <Input
                          type="number"
                          inputMode="numeric"
                          min={0}
                          value={form.income}
                          onChange={(e) => updateField("income", e.target.value)}
                          placeholder="600"
                        />
                      </FormControl>
                      <FormDescription>
                        税込の年収を万円単位でご入力ください。
                      </FormDescription>
                      <FormMessage />
                    </FormField>

                    <FormField error={errors.tenure} required>
                      <FormLabel>勤続年数</FormLabel>
                      <FormControl>
                        <Input
                          type="number"
                          inputMode="numeric"
                          min={0}
                          value={form.tenure}
                          onChange={(e) => updateField("tenure", e.target.value)}
                          placeholder="5"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormField>

                    <FormField error={errors.employment} required>
                      <FormLabel>雇用形態</FormLabel>
                      <FormControl>
                        <Select
                          value={form.employment}
                          onChange={(e) => updateField("employment", e.target.value)}
                        >
                          {EMPLOYMENT_OPTIONS.map((o) => (
                            <option key={o.value} value={o.value}>
                              {o.label}
                            </option>
                          ))}
                        </Select>
                      </FormControl>
                      <FormMessage />
                    </FormField>

                    <FormField error={errors.existingDebt}>
                      <FormLabel>既存借入（月額・円）</FormLabel>
                      <FormControl>
                        <Input
                          type="number"
                          inputMode="numeric"
                          min={0}
                          value={form.existingDebt}
                          onChange={(e) =>
                            updateField("existingDebt", e.target.value)
                          }
                          placeholder="0"
                        />
                      </FormControl>
                      <FormDescription>
                        他の住宅ローン・カードローン等の月々返済額（任意）。
                      </FormDescription>
                      <FormMessage />
                    </FormField>
                  </CardContent>

                  {/* Debt-to-income affordance */}
                  {dti !== null && (
                    <CardContent className="pt-0">
                      <Alert variant={dtiOver ? "warning" : "success"}>
                        {dtiOver ? (
                          <IconAlertTriangle aria-hidden="true" />
                        ) : (
                          <IconCircleCheck aria-hidden="true" />
                        )}
                        <AlertTitle as="h3">
                          返済負担率 {formatPercent(dti, { maximumFractionDigits: 1 })}
                        </AlertTitle>
                        <AlertDescription>
                          {dtiOver
                            ? "月々返済額が月収の約35%を超えています。借入希望額の引き下げまたは返済期間の延長をご検討ください。本審査では追加書類が必要になる場合があります。"
                            : "返済負担率は当行の目安（35%以内）に収まっています。"}
                          <span className="mt-1 block">
                            想定月々返済額{" "}
                            {formatCurrency(summary.monthlyPayment + existingMonthly)} / 月収目安{" "}
                            {formatCurrency(Math.round((incomeManen * 10_000) / 12))}
                          </span>
                        </AlertDescription>
                        <Progress
                          value={Math.min(100, dti * 100)}
                          className="mt-2 h-2 w-full"
                          aria-label="返済負担率"
                        />
                      </Alert>
                    </CardContent>
                  )}
                </Card>
              </section>

              {/* Documents */}
              <section aria-labelledby="docs-heading">
                <Card>
                  <CardHeader>
                    <CardTitle as="h2" id="docs-heading">
                      書類アップロード
                    </CardTitle>
                    <CardDescription>
                      各区分の書類をアップロードしてください。複数ファイルの添付・削除が可能です。
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="grid gap-6">
                    {DOC_CATEGORIES.map((c) => (
                      <DocumentUploader key={c.key} category={c} />
                    ))}
                  </CardContent>
                </Card>
              </section>

              {/* Consent */}
              <section aria-labelledby="consent-heading">
                <Card>
                  <CardHeader>
                    <CardTitle as="h2" id="consent-heading">
                      同意事項
                    </CardTitle>
                    <CardDescription>
                      お申込みには以下すべてへの同意が必要です。
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="grid gap-4">
                    <Checkbox
                      checked={consentCredit}
                      onCheckedChange={setConsentCredit}
                      label="信用情報機関への照会・登録に同意します"
                      description="仮審査にあたり、指定信用情報機関にお客さまの信用情報を照会・登録します。"
                    />
                    <Checkbox
                      checked={consentTerms}
                      onCheckedChange={setConsentTerms}
                      label="個人情報の取扱い・商品説明事項に同意します"
                      description="プライバシーポリシーおよび重要事項説明の内容に同意します。"
                    />
                    {submitted && !allConsented && (
                      <p role="alert" className="text-xs font-medium text-destructive">
                        お申込みには、すべての同意事項へのチェックが必要です。
                      </p>
                    )}
                  </CardContent>
                </Card>
              </section>

              {/* Submit */}
              <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                <p className="text-xs text-muted-foreground">
                  仮審査は本審査の結果を保証するものではありません。
                </p>
                <Button type="submit" size="lg" className="w-full sm:w-auto">
                  仮審査を申し込む
                </Button>
              </div>
            </Form>
          </>
        )}
      </Container>
    </main>
  );
}

/* ------------------------------------------------------------------ */
/* Result screen                                                       */
/* ------------------------------------------------------------------ */

function ResultScreen({
  result,
  steps,
  onReset,
}: {
  result: DecisionResult;
  steps: { label: string; state: "completed" | "current" | "upcoming" }[];
  onReset: () => void;
}) {
  const config = {
    approved: {
      icon: <IconCircleCheck aria-hidden="true" />,
      badge: "承認" as const,
      badgeVariant: "success" as const,
      title: "仮審査の結果：承認",
      alertVariant: "success" as const,
    },
    conditional: {
      icon: <IconAlertTriangle aria-hidden="true" />,
      badge: "要審査" as const,
      badgeVariant: "warning" as const,
      title: "仮審査の結果：条件付き（要本審査）",
      alertVariant: "warning" as const,
    },
    declined: {
      icon: <IconCircleX aria-hidden="true" />,
      badge: "否決" as const,
      badgeVariant: "destructive" as const,
      title: "仮審査の結果：否決",
      alertVariant: "destructive" as const,
    },
  }[result.decision];

  return (
    <main className="min-h-full bg-background py-8 sm:py-10">
      <Container size="md" className="flex flex-col gap-8">
        <header className="flex flex-col gap-3">
          <Badge variant="info" className="w-fit">
            ぐんじょう銀行
          </Badge>
          <h1 className="text-2xl font-bold tracking-tight text-foreground sm:text-3xl">
            住宅ローン仮審査申込
          </h1>
          <div className="overflow-x-auto">
            <Stepper steps={steps} aria-label="申込ステップ" />
          </div>
        </header>

        <Card>
          <CardContent className="py-8">
            <StatusScreen
              className="min-h-0 py-0"
              headingLevel={2}
              icon={config.icon}
              title={
                <span className="flex flex-wrap items-center justify-center gap-2">
                  {config.title}
                  <Badge variant={config.badgeVariant}>{config.badge}</Badge>
                </span>
              }
              description={result.reason}
            />

            {result.decision !== "declined" && (
              <div className="mx-auto mt-6 max-w-md">
                <Statistic
                  label="借入可能額の目安"
                  value={formatCurrency(result.maxLoan)}
                  tone="positive"
                  hint="本審査により変動する場合があります"
                />
              </div>
            )}

            {result.conditions.length > 0 && (
              <Alert variant={config.alertVariant} className="mx-auto mt-6 max-w-xl">
                {config.icon}
                <AlertTitle as="h3">
                  {result.decision === "approved" ? "ご融資の条件" : "本審査に必要な事項"}
                </AlertTitle>
                <AlertDescription>
                  <ul className="ml-4 list-disc space-y-1">
                    {result.conditions.map((c) => (
                      <li key={c}>{c}</li>
                    ))}
                  </ul>
                </AlertDescription>
              </Alert>
            )}

            <dl className="mx-auto mt-6 grid max-w-md grid-cols-2 gap-2 rounded-lg border border-border bg-muted/30 p-4 text-sm">
              <dt className="text-muted-foreground">受付番号</dt>
              <dd className="text-right font-medium tabular-nums text-foreground">
                {result.receiptNo}
              </dd>
              <dt className="text-muted-foreground">受付日時</dt>
              <dd className="text-right font-medium tabular-nums text-foreground">
                {result.timestamp}
              </dd>
            </dl>

            <div className="mt-8 flex justify-center">
              <Button variant="outline" onClick={onReset}>
                シミュレーションに戻る
              </Button>
            </div>
          </CardContent>
        </Card>
      </Container>
    </main>
  );
}
